INSERT INTO question_choices (question_id, choice_number, choice_text) VALUES
(160, 1, 'They relied on outdated neurological models that incorrectly assumed the brain lacked the capacity to process two languages.'),
(160, 2, 'They were conducted exclusively with adult immigrants who had already passed the critical period for language acquisition.'),
(160, 3, 'They failed to account for socioeconomic factors, confusing the effects of poverty with those of bilingualism.'),
(160, 4, 'They used standardized tests designed for monolingual speakers, which systematically disadvantaged bilingual participants.'),
(161, 1, 'Bilingual education programs for Indigenous communities have been less effective than expected due to insufficient government funding.'),
(161, 2, 'Bilingual education can function as a means of cultural regeneration, helping restore linguistic heritage that assimilationist policies had nearly destroyed.'),
(161, 3, 'Indigenous language programs have succeeded primarily because they avoid the dual-language immersion model used in mainstream education.'),
(161, 4, 'The revival of Indigenous languages through bilingual education has come at the cost of lower academic achievement in dominant languages.'),
(162, 1, 'delay the onset of dementia symptoms by as much as five years'),
(162, 2, 'eliminate the risk of age-related cognitive decline entirely in healthy adults'),
(162, 3, 'reverse the neurological damage caused by early-childhood language deprivation'),
(162, 4, 'compensate for the cognitive deficits associated with limited formal education');

